import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import Register from './components/Register';
import Dashboard from './components/Dashboard';
import RFIDIntegration from './components/RFIDIntegration';
import Inventory from './components/Inventory';
import Footer from './components/Footer';
import UploadRFID from './components/UploadRFID';
import NotFound from './components/NotFound';
import 'bootstrap/dist/css/bootstrap.min.css';

// Protected route authentication check
const isAuthenticated = () => !!localStorage.getItem('token');

function App() {
  return (
    <Router>
      <div style={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden'
      }}>
        <style>{`
          .hide-scrollbar {
            scrollbar-width: none; /* Firefox */
            -ms-overflow-style: none; /* IE 10+ */
          }
          .hide-scrollbar::-webkit-scrollbar {
            display: none; /* Chrome/Safari/Webkit */
          }
        `}</style>
        <Routes>
          <Route path="/login" element={<><Login /><Footer /></>} />
          <Route path="/register" element={<><Register /><Footer /></>} />
          <Route 
            path="/dashboard" 
            element={isAuthenticated() ? <Dashboard /> : <Navigate to="/login" />} 
          />
          <Route 
            path="/rfid-integration" 
            element={isAuthenticated() ? <RFIDIntegration /> : <Navigate to="/login" />} 
          />
          <Route 
            path="/inventory" 
            element={isAuthenticated() ? <Inventory clientCode={localStorage.getItem('userInfo') ? JSON.parse(localStorage.getItem('userInfo')).ClientCode : ''} /> : <Navigate to="/login" />} 
          />
          <Route 
            path="/upload-rfid" 
            element={isAuthenticated() ? <UploadRFID /> : <Navigate to="/login" />} 
          />
          <Route path="/" element={<Navigate to="/login" />} />
          <Route path="*" element={<NotFound />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
